                    </div>

                    <div className="grid grid-cols-1 lg:grid-cols-4 gap-6 mt-6">
                        <Card 
                            title="Email Traffic Trends" 
                            className="lg:col-span-3"
                            titleActions={
                                <div className="w-36">
