        { initials: 'AH', name: 'a.hossam@roaya.co', sent: 8, received: 12, status: 'active', risk: 'low risk' },
        { initials: 'OD', name: 'o.diyaa@roaya.co', sent: 6, received: 9, status: 'active', risk: 'low risk' },
        { initials: 'AE', name: 'a.elbeltagy@roaya.co', sent: 3, received: 4, status: 'active', risk: 'low risk' },
    ], []);

    // Updated with InternalContributors data
    const internalContributors = useMemo(() => [
        { initials: 'DO', name: 'diyaaoda@roaya.co', count: 435, status: 'active', risk: 'low risk' },
        { initials: 'AA', name: 'aali@roaya.co', count: 315, status: 'active', risk: 'low risk' },
        { initials: 'AH', name: 'a.hossam@roaya.co', count: 309, status: 'active', risk: 'low risk' },
        { initials: 'AY', name: 'a.younis@roaya.co', count: 307, status: 'active', risk: 'low risk' },
        { initials: 'OD', name: 'o.diyaa@roaya.co', count: 272, status: 'active', risk: 'low risk' },
    ], []);

    // Updated with ExternalContributors data
    const externalContributors = useMemo(() => [
        { initials: 'NC', name: 'notifications@tasks.clickup.com', count: 703, status: 'external', risk: 'low risk' },
        { initials: 'CX', name: 'cortex@xdr.paloaltonetworks.com', count: 667, status: 'external', risk: 'low risk' },
        { initials: 'NS', name: 'noreply@site24x7.com', count: 553, status: 'external', risk: 'low risk' },
        { initials: 'JW', name: 'jira@worldposta.atlassian.net', count: 171, status: 'external', risk: 'low risk' },
        { initials: 'WS', name: 'wp-support@roaya.co', count: 72, status: 'external', risk: 'low risk' },
    ], []);

    // Helper functions for rendering tags
    const getRiskTagClass = (risk: string) => {
        switch (risk.toLowerCase()) {
            case 'critical': return 'bg-red-600 text-white';
            case 'high': return 'bg-yellow-500 text-white';
            case 'medium': return 'bg-blue-500 text-white';
            case 'low risk': return 'bg-green-500 text-white';
            default: return 'bg-gray-500 text-white';
        }
    };
    const getStatusTagClass = (status: string) => {
        if (status === 'active') return 'bg-green-100 text-green-700';
        if (status === 'external') return 'bg-blue-100 text-blue-700';
        return 'bg-yellow-100 text-yellow-700';
    };

    const getStatusChipClass = (status: SmtpLogStatus) => {
        const baseClasses = 'px-2 inline-flex text-xs leading-5 font-semibold rounded-full';
        switch (status) {
            case 'Passed':
                return `${baseClasses} bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-300`;
            case 'Archived':
                return `${baseClasses} bg-blue-100 text-blue-800 dark:bg-blue-900 dark:text-blue-300`;
            case 'Rejected (Data)':
