                            {analysisResult.recommendations.map((item, i) => <li key={`rec-${i}`}>{item}</li>)}
                        </ul>
                    </div>}
                </div>
            )
        }
        return null;
    }


    return (
        <div className="space-y-6">
            <div role="tablist" className="inline-flex space-x-1 p-1 bg-gray-200/50 dark:bg-slate-700/50 rounded-lg">
