                                                                </button>
                                                            </li>
                                                        )}
                                                    </ul>
                                                </div>
                                            )}
                                        </div>
                                    </td>
                                </tr>
                            ))}
                              {filteredTickets.length === 0 && (
                                <tr>
                                    <td colSpan={isAdmin ? 8 : 7} className="text-center py-10 text-gray-500 dark:text-gray-400">
