                    </table>
                     <Pagination
                        currentPage={currentPage}
                        totalItems={filteredTickets.length}
                        itemsPerPage={rowsPerPage}
                        onPageChange={setCurrentPage}
                        onItemsPerPageChange={(value) => {
                            setRowsPerPage(value);
                            setCurrentPage(1);
